#!/usr/bin/env python3
"""Bulk-migrate all workspace specs to aligned behavior-first body structure."""

from __future__ import annotations

import tomllib
from pathlib import Path

ROOT = Path(__file__).resolve().parents[2]
MARKER = "<!-- aligned-structure:v1 -->"


def find_spec_dirs(root: Path) -> list[Path]:
    return sorted({p.parent for p in root.glob("**/.spec/specs/*/spec.toml")})


def first_paragraph(markdown: str) -> str:
    lines = markdown.splitlines()
    started = False
    buf: list[str] = []
    for raw in lines:
        line = raw.strip()
        if line.startswith("<!--") and line.endswith("-->"):
            continue
        if not started:
            if not line:
                continue
            if line.startswith("#"):
                continue
            started = True
            buf.append(line)
            continue
        if not line:
            break
        if line.startswith("#"):
            break
        buf.append(line)
    return " ".join(buf).strip()


def to_bullets(values: list[str], fallback: str) -> str:
    if not values:
        return f"- {fallback}"
    return "\n".join(f"- {v}" for v in values)


def extract_strings(items, key: str) -> list[str]:
    out: list[str] = []
    if not isinstance(items, list):
        return out
    for item in items:
        if isinstance(item, dict):
            value = item.get(key)
            if isinstance(value, str) and value.strip():
                out.append(value.strip())
        elif isinstance(item, str) and item.strip():
            out.append(item.strip())
    return out


def build_body(spec: dict, original: str, spec_id: str) -> str:
    title = spec.get("title") or spec.get("slug") or spec_id
    story = first_paragraph(original)
    if not story:
        story = f"This spec defines the intended behavior contract for {title}."

    contract_statements = extract_strings(spec.get("expected_properties"), "statement")
    if not contract_statements:
        contract_statements = extract_strings(spec.get("acceptance_criteria"), "statement")[:4]

    validation_steps: list[str] = []
    validation_steps.extend(
        f"Contract clause validation: {s}" for s in extract_strings(spec.get("acceptance_criteria"), "statement")
    )
    validation_steps.extend(extract_strings(spec.get("evidence_requirements"), "description"))
    validation_steps.append(
        "Triangulate behavior with executable checks, natural-language clauses, and code/schema/API references when available."
    )

    related_tickets: list[str] = []
    related_tickets.extend(extract_strings(spec.get("related_tickets"), ""))
    # extract_strings cannot handle plain list via empty key; handle directly:
    if isinstance(spec.get("related_tickets"), list):
        for item in spec["related_tickets"]:
            if isinstance(item, str) and item.strip() and item.strip() not in related_tickets:
                related_tickets.append(item.strip())

    if isinstance(spec.get("ticket_ids"), list):
        for tid in spec["ticket_ids"]:
            if isinstance(tid, str) and tid.strip():
                related_tickets.append(f"ticket id: {tid.strip()}")

    legacy = original.strip()
    if not legacy:
        legacy = "(no previous body content)"

    parts = [
        MARKER,
        "",
        "# Summary",
        "",
        story,
        "",
        "## Behavior Story",
        "",
        story,
        "",
        "## Provided Surface Contracts",
        "",
        to_bullets(contract_statements, "Define provided contracts for this behavior slice."),
        "",
        "## Required Validation",
        "",
        to_bullets(validation_steps, "Define required validation and evidence for this contract."),
        "",
        "## Related Implementation Tickets",
        "",
        to_bullets(related_tickets, "No related implementation ticket is linked yet."),
        "",
        "## Background Knowledge References",
        "",
        "- Prefer entity references and context rendering over embedding fully expanded payloads in this spec body.",
        "",
        "## Legacy Content (Preserved)",
        "",
        legacy,
        "",
    ]
    return "\n".join(parts)


def main() -> int:
    migrated = 0
    already = 0
    missing_body_created = 0

    for spec_dir in find_spec_dirs(ROOT):
        spec_path = spec_dir / "spec.toml"
        body_path = spec_dir / "body.md"

        with spec_path.open("rb") as fh:
            spec = tomllib.load(fh)

        if body_path.exists():
            original = body_path.read_text(encoding="utf-8")
        else:
            original = ""
            missing_body_created += 1

        if original.lstrip().startswith(MARKER):
            already += 1
            continue

        new_body = build_body(spec, original, spec.get("id", spec_dir.name))
        body_path.write_text(new_body, encoding="utf-8")
        migrated += 1

    print(f"migrated={migrated} already_aligned={already} created_missing_body={missing_body_created}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())

